// And groups predicates with the AND operator between them.
func And(predicates ...predicate.SeriesProvider) predicate.SeriesProvider {
	return predicate.SeriesProvider(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.SeriesProvider) predicate.SeriesProvider {
	return predicate.SeriesProvider(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.SeriesProvider) predicate.SeriesProvider {
	return predicate.SeriesProvider(sql.NotPredicates(p))
}
